package be.schaubroeck.lpb.rkm.rekenmotor.cache;

import be.schaubroeck.lpb.rkm.rekenmotor.cache.CacheContext.Scope;
import be.schaubroeck.lpb.tools.DmfaVerminderingsPercentage;
import be.schaubroeck.lpb.tools.criteria.CriteriaBuilder;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplCodeVermin;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import be.schaubroeck.lpb.tools.service.DmfaVerminderingsPercentageService;
import be.schaubroeck.lpb.tools.util.TimeLogContext;
import lombok.Data;
import org.joda.time.LocalDate;
import org.springframework.beans.factory.annotation.Autowired;

import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class CachedDmfaVerminderingsPercentageService implements CachedService, DmfaVerminderingsPercentageService {

    @Autowired
    private DmfaVerminderingsPercentageService dmfaVerminderingsPercentageService;

    private static final ThreadLocal<CachedDmfaVerminderingsPercentageBuffer> BUFFER = new ThreadLocal<>();

    public CachedDmfaVerminderingsPercentageService() {
        super();
        CacheContext.getInstance().registerCachedServices(this, Scope.ADMIN);
    }

    @Override
    public DmfaVerminderingsPercentage getByWerkgeversCategorieWerknemersKengetalVerminderingsCodeDatum(
            WerkgeversCategorie werkgeversCategorie,
            DmfapplWnkengetal werknemersKengetal, DmfapplCodeVermin verminderingsCode, LocalDate datum) {
        TimeLogContext.getInstance()
                .startTimeLogging("CachedDmfaVerminderingsPercentageService.getByWerkgeversCategorieWerknemersKengetalVerminderingsCodeDatum");
        CachedDmfaVerminderingsPercentageBuffer buffer = CachedDmfaVerminderingsPercentageService.getBuffer();
        DmfaVerminderingsPercentageKey key = new DmfaVerminderingsPercentageKey(werkgeversCategorie, werknemersKengetal, verminderingsCode, datum);
        DmfaVerminderingsPercentage result;
        if (!buffer.containsKey(key)) {
            result = dmfaVerminderingsPercentageService
                    .getByWerkgeversCategorieWerknemersKengetalVerminderingsCodeDatum(werkgeversCategorie, werknemersKengetal, verminderingsCode, datum);
            buffer.put(key, result);
        } else {
            result = buffer.get(key);
        }
        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }

    @Override
    public void clearCache() {
        CachedDmfaVerminderingsPercentageService.getBuffer().clear();
    }

    private static class CachedDmfaVerminderingsPercentageBuffer {

        private final Map<DmfaVerminderingsPercentageKey, DmfaVerminderingsPercentage> dmfaVerminderingsPercentageBuffer = new HashMap<>();

        public DmfaVerminderingsPercentage get(DmfaVerminderingsPercentageKey key) {
            return dmfaVerminderingsPercentageBuffer.get(key);
        }

        public void put(DmfaVerminderingsPercentageKey key, DmfaVerminderingsPercentage dmfaVerminderingsPercentage) {
            dmfaVerminderingsPercentageBuffer.put(key, dmfaVerminderingsPercentage);
        }

        public boolean containsKey(DmfaVerminderingsPercentageKey key) {
            return dmfaVerminderingsPercentageBuffer.containsKey(key);
        }

        public void clear() {
            dmfaVerminderingsPercentageBuffer.clear();
        }
    }

    private static CachedDmfaVerminderingsPercentageBuffer getBuffer() {
        CachedDmfaVerminderingsPercentageBuffer returnValue = BUFFER.get();
        if (returnValue == null) {
            returnValue = new CachedDmfaVerminderingsPercentageBuffer();
            BUFFER.set(returnValue);
        }
        return returnValue;
    }

    @Data
    private static class DmfaVerminderingsPercentageKey {

        private final WerkgeversCategorie werkgeversCategorie;
        private final DmfapplWnkengetal werknemersKengetal;
        private final DmfapplCodeVermin verminderingsCode;
        private final LocalDate datum;
    }

    //Forwarding naar Standard...Service, we gebruiken hier geen overerving omdat we de @Transcational willen vermijden.

    @Override
    public List<DmfaVerminderingsPercentage> findAll() {
        return dmfaVerminderingsPercentageService.findAll();
    }

    @Override
    public DmfaVerminderingsPercentage create(DmfaVerminderingsPercentage constant) {
        return dmfaVerminderingsPercentageService.create(constant);
    }

    @Override
    public void update(DmfaVerminderingsPercentage constant) {
        dmfaVerminderingsPercentageService.update(constant);
    }

    @Override
    public void delete(DmfaVerminderingsPercentage constant) {
        dmfaVerminderingsPercentageService.delete(constant);
    }

    @Override
    public DmfaVerminderingsPercentage getById(Integer id) {
        return dmfaVerminderingsPercentageService.getById(id);
    }

    @Override
    public DmfaVerminderingsPercentage getById(Integer id, String fetchFields) {
        return dmfaVerminderingsPercentageService.getById(id, fetchFields);
    }

    @Override
    public DmfaVerminderingsPercentage getByCriteria(CriteriaBuilder cb) {
        return dmfaVerminderingsPercentageService.getByCriteria(cb);
    }


    @Override
    public List<DmfaVerminderingsPercentage> findAll(String fetchFields) {
        return dmfaVerminderingsPercentageService.findAll(fetchFields);
    }

    @Override
    public List<DmfaVerminderingsPercentage> findByCriteria(CriteriaBuilder cb) {
        return dmfaVerminderingsPercentageService.findByCriteria(cb);
    }

    @Override
    public Integer countByCriteria(CriteriaBuilder cb) {
        return dmfaVerminderingsPercentageService.countByCriteria(cb);
    }

    @Override
    public Map<Integer, DmfaVerminderingsPercentage> cacheByCriteria(CriteriaBuilder cb) {
        return dmfaVerminderingsPercentageService.cacheByCriteria(cb);
    }

    @Override
    public DmfaVerminderingsPercentage getByCriteriaTemporalFree(CriteriaBuilder cb) {
        return dmfaVerminderingsPercentageService.getByCriteriaTemporalFree(cb);
    }

    @Override
    public List<DmfaVerminderingsPercentage> findByCriteriaTemporalFree(CriteriaBuilder cb) {
        return dmfaVerminderingsPercentageService.findByCriteriaTemporalFree(cb);
    }
}
